// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Helper to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const lower = condition.toLowerCase();
    if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
    if (lower.includes('cloudy') || lower.includes('overcast')) return '☁️';
    if (lower.includes('rainy') || lower.includes('rain')) return '🌧️';
    if (lower.includes('snow')) return '❄️';
    if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
    if (lower.includes('wind')) return '💨';
    if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
    return '🌤️'; // Default partly cloudy
  };

  const weatherEmoji = getWeatherEmoji(props.condition);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Header: City and Condition */}
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Row gap="var(--ggui-spacing-3)" align="center">
                <Icon name={weatherEmoji} size={48} color="var(--ggui-color-primary-600)" />
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
              </Row>
            </Stack>

            <Divider margin="var(--ggui-spacing-3)" />

            {/* Large Temperature Display */}
            <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
              <Stack align="center" gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-primary-700)">CURRENT TEMPERATURE</Text>
                <Heading level={1} color="var(--ggui-color-primary-900)">
                  {props.temperature}°{props.unit}
                </Heading>
              </Stack>
            </Box>

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-4)" justify="between" wrap>
              <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border={false} style={{ flex: 1, minWidth: '140px' }}>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={28} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Card>
              <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border={false} style={{ flex: 1, minWidth: '140px' }}>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={28} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
                </Stack>
              </Card>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
              <Row gap="var(--ggui-spacing-2)" justify="between" align="stretch" wrap>
                {props.forecast.map((dayForecast, index) => (
                  <Card key={index} shadow="sm" padding="var(--ggui-spacing-3)" radius="md" border={false} style={{ flex: '1 1 auto', minWidth: '100px', textAlign: 'center' }}>
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      {dayForecast.day && (
                        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">{dayForecast.day}</Text>
                      )}
                      {dayForecast.icon && (
                        <Icon name={dayForecast.icon} size={32} color="var(--ggui-color-primary-600)" />
                      )}
                      {(dayForecast.high !== undefined || dayForecast.low !== undefined) && (
                        <Stack gap="var(--ggui-spacing-1)" align="center">
                          {dayForecast.high !== undefined && (
                            <Text variant="bodySmall" color="var(--ggui-color-onSurface)" weight="semibold">
                              {dayForecast.high}°
                            </Text>
                          )}
                          {dayForecast.low !== undefined && (
                            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                              {dayForecast.low}°
                            </Text>
                          )}
                        </Stack>
                      )}
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

