// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [nameInlineError, setNameInlineError] = useState('');
  const [emailInlineError, setEmailInlineError] = useState('');

  // Helper function: validate email format
  // Helper function: validate email format
  const isValidEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  // Helper function: inline validation for name
  const validateName = (value: string) => {
    if (value.trim().length === 0) {
      setNameInlineError('Name is required');
    } else {
      setNameInlineError('');
    }
  };

  // Helper function: inline validation for email
  const validateEmail = (value: string) => {
    if (value.trim().length === 0) {
      setEmailInlineError('Email is required');
    } else if (!isValidEmail(value)) {
      setEmailInlineError('Please enter a valid email address');
    } else {
      setEmailInlineError('');
    }
  };

  // Helper function: validate step 1
  const isStep1Valid = (): boolean => {
    const nameValid = name.trim().length > 0;
    const emailValid = email.trim().length > 0 && isValidEmail(email);

    if (!nameValid) setNameError('Name is required');
    else setNameError('');

    if (!emailValid) {
      if (email.trim().length === 0) setEmailError('Email is required');
      else setEmailError('Please enter a valid email address');
    } else setEmailError('');

    return nameValid && emailValid;
  };

  // Helper function: check if Next button should be enabled
  const isNextEnabled = (): boolean => {
    switch (currentStep) {
      case 1:
        return name.trim().length > 0 && email.trim().length > 0 && isValidEmail(email);
      case 2:
        return satisfaction.length > 0;
      case 3:
        return true; // Feature selection is optional
      case 4:
        return true; // Comments step, can move forward
      case 5:
        return true; // Review step, can submit
      default:
        return false;
    }
  };

  // Handle Next button
  const handleNext = () => {
    if (currentStep === 1 && !isStep1Valid()) return;
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    } else if (currentStep === 4) {
      setCurrentStep(5); // Move to review (step 5)
    } else if (currentStep === 5) {
      handleSubmit();
    }
  };
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle form submission
  const handleSubmit = () => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features: selectedFeatures,
      comments: comments.trim(),
    });
  };

  // Handle feature checkbox toggle
  const handleFeatureToggle = (feature: string) => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Bar */}
        <Box as="section" role="region" aria-label="Survey Progress">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">
            Step {currentStep} of 5
          </Text>
          <Spacer size={12} />
          <Progress value={currentStep} max={5} variant="default" size="md" />
        </Box>
        {currentStep === 1 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Personal Information</Heading>
            <Input
              label="Name"
              placeholder="Enter your name"
              value={name}
              onChange={(val) => {
                setName(val);
                validateName(val);
              }}
              required
              error={nameInlineError}
            />
            <Input
              label="Email"
              type="email"
              placeholder="your.email@example.com"
              value={email}
              onChange={(val) => {
                setEmail(val);
                validateEmail(val);
              }}
              required
              error={emailInlineError}
            />
          </Stack>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>How satisfied are you?</Heading>
            <RadioGroup
              label="Satisfaction Rating"
              value={satisfaction}
              onChange={setSatisfaction}
              options={props.satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label: label,
              }))}
              direction="vertical"
            />
          </Stack>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>What features interest you?</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Select all that apply
            </Text>
            <Stack gap="var(--ggui-spacing-3)">
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={selectedFeatures.includes(feature)}
                  onChange={() => handleFeatureToggle(feature)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {/* Step 4: Comments Textarea */}
        {currentStep === 4 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Additional Comments</Heading>
            <TextArea
              label="Comments (Optional)"
              placeholder="Share any additional feedback or comments..."
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
            />
          </Stack>
        )}

        {/* Step 5: Review Your Answers */}
        {/* Step 5: Review Your Answers */}
        {currentStep === 5 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Review Your Answers</Heading>
            <Card padding="var(--ggui-spacing-4)" shadow="md">
              <Stack gap="var(--ggui-spacing-4)">
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                  <Text variant="body">{name}</Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                  <Text variant="body">{email}</Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                  <Text variant="body">
                    {satisfaction && props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}
                  </Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                  <Stack gap="var(--ggui-spacing-2)" direction="horizontal" wrap>
                    {selectedFeatures.length > 0 ? (
                      selectedFeatures.map((feature) => (
                        <Badge key={feature} variant="primary" size="sm">
                          {feature}
                        </Badge>
                      ))
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        None selected
                      </Text>
                    )}
                  </Stack>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                  <Text variant="body">
                    {comments.length > 0 ? comments : 'No additional comments'}
                  </Text>
                </div>
              </Stack>
            </Card>
          </Stack>
        )}



        {/* Navigation Buttons */}
        {/* Navigation Buttons */}
        <Stack direction="horizontal" justify="between" gap="var(--ggui-spacing-3)">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Button
            variant="primary"
            onClick={handleNext}
            disabled={!isNextEnabled()}
          >
            {currentStep === 4 ? 'Submit' : 'Next'}
           >
            {currentStep === 5 ? 'Submit' : 'Next'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

