// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper: Priority badge variant mapping
const getPriorityVariant = (priority?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' => {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
};

// Helper: Get color variable for priority
const getPriorityColor = (priority?: string): string => {
  switch (priority) {
    case 'high': return 'var(--ggui-color-error-500)';
    case 'medium': return 'var(--ggui-color-warning-500)';
    case 'low': return 'var(--ggui-color-success-500)';
    default: return 'var(--ggui-color-outline)';
  }
};

// Helper: Extract initials from assignee string
const getInitials = (assignee?: string): string => {
  if (!assignee) return '?';
  return assignee
    .split(' ')
    .map(part => part[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);
};

// TaskCard sub-component
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  onMove: (taskId: string, targetColumn: string) => void;
  onEdit: (taskId: string, newTitle: string) => void;
  columns: Array<{ id?: string; name?: string }>;
}

function TaskCard({ task, onMove, onEdit, columns }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleSaveEdit = () => {
    if (task.id && editTitle.trim()) {
      onEdit(task.id, editTitle);
      setIsEditing(false);
    }
  };

  const handleMoveTask = (targetColumnId: string) => {
    if (task.id) {
      onMove(task.id, targetColumnId);
    }
    setShowMoveMenu(false);
  };

  const otherColumns = columns.filter(col => col.id !== task.column);

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
      <Stack gap="var(--ggui-spacing-2)">
        {/* Task Title */}
       {isEditing ? (
         <Stack gap="var(--ggui-spacing-2)">
           <Input
             label="Edit task"
             value={editTitle}
             onChange={setEditTitle}
             onKeyDown={(e) => {
               if (e.key === 'Enter') {
                 handleSaveEdit();
               } else if (e.key === 'Escape') {
                 setIsEditing(false);
               }
             }}
             placeholder="Task title"
           />
         </Stack>
       ) : (
         <Text
           variant="body"
           weight="semibold"
           as={Clickable}
           onDoubleClick={() => setIsEditing(true)}
           style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-1)' }}
         >
           {task.title || 'Untitled Task'}
         </Text>
       )}

        {/* Priority Badge + Assignee + Due Date */}
        <Row gap="var(--ggui-spacing-2)" align="center">
          <Badge variant={getPriorityVariant(task.priority)} size="sm">
            {task.priority || 'none'}
          </Badge>
          {task.assignee && (
            <Tooltip content={task.assignee} position="top">
              <Avatar name={task.assignee} size="sm" />
            </Tooltip>
          )}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {new Date(task.dueDate).toLocaleDateString()}
            </Text>
          )}
        </Row>

        {/* Action Buttons */}
        {isEditing && (
          <Row gap="var(--ggui-spacing-2)" justify="end">
            <Button size="sm" variant="ghost" onClick={() => setIsEditing(false)}>
              Cancel
            </Button>
            <Button size="sm" variant="primary" onClick={handleSaveEdit}>
              Save
            </Button>
          </Row>
        )}

        {!isEditing && (
          <Row gap="var(--ggui-spacing-2)">
            <Button size="xs" variant="ghost" onClick={() => setIsEditing(true)}>
              <Icon name="edit" size={14} />
            </Button>
            <Dropdown
              trigger={<Button size="xs" variant="ghost"><Icon name="arrow-right" size={14} /></Button>}
              options={otherColumns.map(col => ({
                value: col.id || '',
                label: `Move to ${col.name}`,
              }))}
              value=""
              onChange={(colId) => handleMoveTask(colId)}
              placement="bottom-end"
            />
          </Row>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state for tasks (enhanced with props initial data)
  const [tasks, setTasks] = useState(props.tasks || []);
  const [activeAddColumn, setActiveAddColumn] = useState<string | null>(null);
  const [newTaskTitles, setNewTaskTitles] = useState<Record<string, string>>({});
  const [newTaskPriorities, setNewTaskPriorities] = useState<Record<string, 'low' | 'medium' | 'high'>>({});

  // Update local tasks when props change
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle stream updates (real-time from other team members)
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks(prev => [...prev, task]);
      } else if (action === 'move' && task?.id) {
        setTasks(prev =>
          prev.map(t => t.id === task.id ? { ...t, column: task.column } : t)
        );
      } else if (action === 'edit' && task?.id) {
        setTasks(prev =>
          prev.map(t => t.id === task.id ? { ...t, ...task } : t)
        );
      } else if (action === 'delete' && task?.id) {
        setTasks(prev => prev.filter(t => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks(prev =>
      prev.map(t => t.id === taskId ? { ...t, column: targetColumn } : t)
    );
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

   const handleEditTask = useCallback((taskId: string, newTitle: string) => {
     setTasks(prev =>
       prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t)
     );
     taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo', title: newTitle } });
   }, [taskUpdate, tasks]);

   const handleAddTask = useCallback((columnId: string) => {
    const title = newTaskTitles[columnId] || 'New Task';
    const priority = newTaskPriorities[columnId] || 'medium';
    const newTask: typeof tasks[0] = {
      id: `task-${Date.now()}`,
      title,
      priority,
      column: columnId,
    };
    setTasks(prev => [...prev, newTask]);
    setNewTaskTitles(prev => ({ ...prev, [columnId]: '' }));
    setActiveAddColumn(null);
    taskUpdate({ action: 'create', taskId: newTask.id!, data: { column: columnId } });
  }, [newTaskTitles, taskUpdate]);

  // Computed: tasks grouped by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns?.forEach(col => {
      grouped[col.id || ''] = tasks.filter(t => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  // Computed: summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box
          background="var(--ggui-color-surfaceVariant)"
          padding="var(--ggui-spacing-4)"
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                Task Summary
              </Text>
              <Row gap="var(--ggui-spacing-4)">
                <div>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                    {totalTasks}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    Total Tasks
                  </Text>
                </div>
                <div>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-success-600)">
                    {completedTasks}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    Completed
                  </Text>
                </div>
              </Row>
            </Stack>
            <Progress
              value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
              variant="success"
              size="md"
              style={{ width: '150px' }}
            />
          </Row>
        </Box>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns?.map(column => {
            const columnTasks = tasksByColumn[column.id || ''] || [];
            return (
              <div
                key={column.id}
                style={{
                  flex: '1 1 300px',
                  minWidth: '300px',
                  display: 'flex',
                  flexDirection: 'column',
                }}
              >
                <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
                  <Stack gap="var(--ggui-spacing-4)">
                    {/* Column Header */}
                    <Row justify="between" align="center">
                      <Heading level={4} color="var(--ggui-color-onSurface)">
                        {column.name}
                      </Heading>
                      <Badge variant="secondary" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Row>

                    <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                    {/* Task List */}
                    <Stack gap="var(--ggui-spacing-3)" style={{ minHeight: '200px' }}>
                      {columnTasks.map(task => (
                        <TaskCard
                          key={task.id}
                          task={task}
                          onMove={handleMoveTask}
                          onEdit={handleEditTask}
                          columns={props.columns || []}
                        />
                      ))}
                    </Stack>

                    {/* Add Task Button / Form */}
                    {activeAddColumn === column.id ? (
                       <Stack gap="var(--ggui-spacing-2)">
                         <Input
                           label="Task title"
                           placeholder="Enter task title..."
                           value={newTaskTitles[column.id || ''] || ''}
                           onChange={(val) =>
                             setNewTaskTitles(prev => ({
                               ...prev,
                               [column.id || '']: val,
                             }))
                           }
                         />
                         <Select
                           label="Priority"
                           value={newTaskPriorities[column.id || ''] || 'medium'}
                           onChange={(val) =>
                             setNewTaskPriorities(prev => ({
                               ...prev,
                               [column.id || '']: val as 'low' | 'medium' | 'high',
                             }))
                           }
                           options={[
                             { value: 'low', label: 'Low' },
                             { value: 'medium', label: 'Medium' },
                             { value: 'high', label: 'High' },
                           ]}
                         />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => setActiveAddColumn(null)}
                          >
                            Cancel
                          </Button>
                          <Button
                            size="sm"
                            variant="primary"
                            onClick={() => handleAddTask(column.id || '')}
                          >
                            Add Task
                          </Button>
                        </Row>
                      </Stack>
                    ) : (
                      <Button
                        fullWidth
                        variant="outline"
                        onClick={() => setActiveAddColumn(column.id || '')}
                      >
                        + Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
              </div>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

