};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query)) ||
      (el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories and their colors
  const categories = useMemo(() => {
    const uniqueCats = Array.from(new Set(props.elements.map(el => el.category).filter(Boolean)));
    return uniqueCats.sort();
  }, [props.elements]);

  // Get color for a category
  const getCategoryColor = (category?: string) => {
    if (!category) return { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' };
    return CATEGORY_COLORS[category] || { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' };
  };

  return (
    <Stack gap="var(--ggui-spacing-6)" align="stretch">
