                borderWidth: isSelected ? '2px' : '1px',
              }}
            >
              <Stack gap="var(--ggui-spacing-1)" align="center" justify="center" style={{ height: '100%' }}>
                <Text variant="caption" color={color.text} align="left" style={{ alignSelf: 'flex-start', fontSize: 'var(--ggui-font-size-xs)' }}>
