              <Heading level={2}>{selectedElement.name}</Heading>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedElement(null)}
              >
                Close
              </Button>
            </Row>
            <Divider />
            <Stack gap="var(--ggui-spacing-2)" align="stretch">
              <Row gap="var(--ggui-spacing-4)" justify="start">
                <Stack gap="var(--ggui-spacing-1)" align="stretch">
