/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const isOutOfStock = props.product.stock === 0;
  const isLowStock = props.product.stock && props.product.stock > 0 && props.product.stock <= 5;
  const maxQuantity = props.product.stock || 1;
  const formattedPrice = props.product.price && props.product.currency
    ? `${props.product.currency}${props.product.price.toFixed(2)}`
    : '$0.00';

  // Handlers
  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity((prev) => {
      const newQty = prev + delta;
      return Math.max(1, Math.min(newQty, maxQuantity));
    });
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Helper: Render star rating
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    const stars = [];
    const filledStars = Math.round(rating);
    for (let i = 0; i < 5; i++) {
      const isFilled = i < filledStars;
      stars.push(
        <Icon
          key={i}
          name="star"
          size={16}
          color={isFilled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      );
    }
    return <Row gap="var(--ggui-spacing-1)" align="center">{stars}</Row>;
  };

  // Helper: Render specification table
  const renderSpecifications = () => {
    const specs = props.product.specifications as Array<{ key?: string; value?: string }> | undefined;
    if (!specs || specs.length === 0) {
      return <Text variant="body">No specifications available</Text>;
    }
    return (
      <Table
        columns={[
          { key: 'key', header: 'Property', align: 'left' },
          { key: 'value', header: 'Value', align: 'left' },
        ]}
        data={specs}
        compact
        striped
      />
    );
  };

  // Helper: Render reviews list
  const renderReviews = () => {
    const reviews = props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }> | undefined;
    if (!reviews || reviews.length === 0) {
      return <Text variant="body">No reviews yet</Text>;
    }
    return (
      <Stack gap="var(--ggui-spacing-4)">
        {reviews.map((review, idx) => (
          <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)">
              <Row gap="var(--ggui-spacing-3)" align="center" justify="between">
                <Stack gap="var(--ggui-spacing-1)" direction="horizontal" align="center">
                  <Text variant="label" weight="semibold">{review.author || 'Anonymous'}</Text>
                  {review.rating && <Row gap="var(--ggui-spacing-1)" align="center">{renderStars(review.rating)}</Row>}
                </Stack>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date || 'N/A'}</Text>
              </Row>
              <Text variant="body">{review.text || 'No text provided'}</Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  };

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: <Text variant="body">{props.product.description || 'No description available'}</Text>,
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: renderSpecifications(),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: renderReviews(),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock Status */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            padding="var(--ggui-spacing-6)"
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ minWidth: '300px', width: '100%', maxWidth: '400px', aspectRatio: '1 / 1', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Text variant="bodyLarge" align="center" color="var(--ggui-color-primary-700)" weight="semibold">
              {props.product.name || 'Product Image'}
            </Text>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            {/* Title */}
            <Heading level={1}>{props.product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Text variant="2xl" weight="bold" color="var(--ggui-color-primary-600)">
              {formattedPrice}
            </Text>

            {/* Rating */}
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              {renderStars(props.product.rating)}
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                {props.product.rating ? `${props.product.rating.toFixed(1)}/5` : 'No rating'} ({props.product.reviewCount || 0} reviews)
              </Text>
            </Stack>

            {/* Stock Status Badge */}
            <Box>
              <Badge
                variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}
                size="md"
              >
                {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
              </Badge>
            </Box>
          </Stack>
        </Stack>

        <Divider />

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
          size="md"
        />

