export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Append new message from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Get current typing indicator
  const typingUser = typing.latest?.active ? typing.latest.sender : null;

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender: string;
      messages: Array<{ text: string; timestamp: string }>;
    }> = [];

    messages.forEach((msg) => {
      const sender = msg.sender || 'Unknown';
      const lastGroup = groups[groups.length - 1];

      if (lastGroup && lastGroup.sender === sender) {
        lastGroup.messages.push({
          text: msg.text || '',
          timestamp: msg.timestamp || new Date().toISOString(),
        });
      } else {
        groups.push({
          sender,
          messages: [
            {
              text: msg.text || '',
              timestamp: msg.timestamp || new Date().toISOString(),
            },
          ],
        });
      }
    });

    return groups;
  }, [messages]);

  // Format timestamp for display
  const formatTime = (timestamp: string): string => {
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  return (
    <Stack gap="var(--ggui-spacing-4)" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <Card shadow="sm" padding="var(--ggui-spacing-4)" border={true}>
        <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
          <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
            <Heading level={3}>{props.title}</Heading>
            <Badge variant="primary">{props.participantCount}</Badge>
          </Stack>
          {typingUser && (
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Spinner size={16} color="var(--ggui-color-primary-600)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typingUser} is typing...</Text>
            </Stack>
          )}
        </Row>
      </Card>

      {/* Messages List */}
      <Box
        padding="var(--ggui-spacing-4)"
        background="var(--ggui-color-surface)"
        borderRadius="var(--ggui-shape-radius-lg)"
        aria-live="polite"
        aria-label="Message list"
        style={{
          flex: 1,
          overflowY: 'auto',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-4)',
          border: '1px solid var(--ggui-color-outline)',
        }}
        {groupedMessages.length === 0 ? (
          <Box
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
            }}
          >
            <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet</Text>
          </Box>
        ) : (
           <Stack gap="var(--ggui-spacing-3)" align={isCurrentUser ? 'end' : 'start'}>
                <Text as={Heading} level={6} color="var(--ggui-color-onSurface)" style={{ marginBottom: 'var(--ggui-spacing-2)' }}>
                  {group.sender}
                </Text>
                <Stack
                  key={`${group.sender}-${groupIdx}`}
                  gap="var(--ggui-spacing-2)"
                  align={isCurrentUser ? 'end' : 'start'}
                {group.messages.map((msg, msgIdx) => (
                  <Box
                    key={`${groupIdx}-${msgIdx}`}
                    padding="var(--ggui-spacing-3)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={
                      isCurrentUser
                        ? 'var(--ggui-color-primary-600)'
                        : 'var(--ggui-color-surfaceVariant)'
                    }
                    role="article"
                    style={{
                      maxWidth: '60%',
