                    }}
                    <Text
                      color={
                        isCurrentUser
                          ? 'white'
                          : 'var(--ggui-color-onSurface)'
                      }
                      color={
                        isCurrentUser
                          ? 'white'
                          : 'var(--ggui-color-onSurface)'
                      }
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
