export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State management
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout>();

  // Merge price updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            // Mark this symbol as updating for animation
            setUpdatingSymbols((prev) => new Set(prev).add(stock.symbol || ''));
            // Clear the updating flag after animation
            if (updateTimeoutRef.current) clearTimeout(updateTimeoutRef.current);
            updateTimeoutRef.current = setTimeout(() => {
              setUpdatingSymbols((prev) => {
                const next = new Set(prev);
                next.delete(stock.symbol || '');
                return next;
              });
            }, 600);

            return {
              ...stock,
              price: priceUpdate.latest.price ?? stock.price,
              change: priceUpdate.latest.change ?? stock.change,
              changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        setLastUpdated(new Date());
        return updated;
      });
    }
  }, [priceUpdate.latest]);

  // Update initial stocks from props when they change
  useEffect(() => {
    setStocks(props.stocks || []);
  }, [props.stocks]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (updateTimeoutRef.current) clearTimeout(updateTimeoutRef.current);
    };
  }, []);

  // Format last updated time
  const lastUpdatedDisplay = useMemo(() => {
    if (!lastUpdated) return 'Never';
    const now = new Date();
    const diffMs = now.getTime() - lastUpdated.getTime();
    const diffSecs = Math.floor(diffMs / 1000);

    if (diffSecs < 60) return `${diffSecs}s ago`;
    if (diffSecs < 3600) return `${Math.floor(diffSecs / 60)}m ago`;
    return lastUpdated.toLocaleTimeString();
  }, [lastUpdated]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            Market Watch
          </Heading>
          <Row align="center" gap="var(--ggui-spacing-2)">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdatedDisplay}
            </Text>
            {marketStatus.latest && (
              <Badge variant={marketStatus.latest.status === 'open' ? 'success' : 'default'} size="sm" aria-label={`Market status: ${marketStatus.latest.status || 'unknown'}`}>
                {marketStatus.latest.status || 'unknown'}
              </Badge>
            )}
          </Row>
        </Stack>

        {/* Stock Grid - Responsive: 3 cols on desktop, 1 on mobile */}
        {/* Stock Grid - Responsive: 3 cols on desktop, 1 on mobile */}
         <Box
           role="region"
           aria-label="Stock prices grid"
           style={{
             display: 'grid',
             gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
             gap: 'var(--ggui-spacing-4)',
           }}
         >
           {stocks.map((stock) => (
             <StockCard
               key={stock.symbol || Math.random()}
               stock={stock}
               isUpdating={updatingSymbols.has(stock.symbol || '')}
             />
           ))}
         </Box>

        {/* Empty state */}
        {(!stocks || stocks.length === 0) && (
          <Alert variant="info">
            No stocks to display. Add stocks to see live price updates.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

