  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
type BoardTask = { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };
const DEFAULT_COLUMNS = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' },
];
const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];
function getPriorityVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<BoardTask[]>([]);
  const [showAddFormByColumn, setShowAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  const columnsSafe = useMemo(() => {
    if (props.columns && props.columns.length > 0) {
      return props.columns.map((column) => ({
        id: column.id || '',
        name: column.name || 'Untitled',
      }));
    }
    return DEFAULT_COLUMNS;
  }, [props.columns]);

  useEffect(() => {
    const normalized = (props.tasks || []).map((task, index) => ({
      id: task.id || `task-${index}-${Date.now()}` ,
      title: task.title || 'Untitled task',
      priority: task.priority || 'low',
      assignee: task.assignee || 'NA',
      column: task.column || 'todo',
      dueDate: task.dueDate || '',
    }));
    setTasksState(normalized);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest;
    const incomingTask = incoming.task;
    const normalizedTask: BoardTask = {
      id: incomingTask.id || `stream-${Date.now()}` ,
      title: incomingTask.title || 'Untitled task',
      priority: incomingTask.priority || 'low',
      assignee: incomingTask.assignee || 'NA',
      column: incomingTask.column || 'todo',
      dueDate: incomingTask.dueDate || '',
    };

    setTasksState((prev) => {
      if (incoming.action === 'delete') {
        return prev.filter((task) => task.id !== normalizedTask.id);
      }
      const idx = prev.findIndex((task) => task.id === normalizedTask.id);
      if (idx === -1) return [...prev, normalizedTask];
      const next = [...prev];
      next[idx] = { ...next[idx], ...normalizedTask };
      return next;
    });
  }, [taskChanged.latest]);

  const tasksByColumn = useMemo(() => {
    return columnsSafe.reduce<Record<string, BoardTask[]>>((acc, column) => {
      acc[column.id] = tasksState.filter((task) => task.column === column.id);
      return acc;
    }, {});
  }, [columnsSafe, tasksState]);

  const totalTasks = tasksState.length;
  const doneColumnId = (columnsSafe.find((column) => (column.name || '').toLowerCase() === 'done')?.id) || 'done';
  const completedCount = tasksState.filter((task) => task.column === doneColumnId).length;

  const moveTask = useCallback((taskId: string, newColumn: string) => {
    setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: newColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  const saveEditTask = useCallback((taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) return;
    const existing = tasksState.find((task) => task.id === taskId);
    if (!existing) return;
    setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: trimmed } : task)));
    taskUpdate({ action: 'edit', taskId, data: { column: existing.column, title: trimmed, priority: existing.priority, assignee: existing.assignee, dueDate: existing.dueDate || '' } });
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, taskUpdate, tasksState]);

  const createTask = useCallback((columnId: string) => {
    const title = (newTaskTitleByColumn[columnId] || '').trim();
    if (!title) return;
    const id = `task-${Date.now()}`;
    const newTask: BoardTask = {
      id,
      title,
      priority: newTaskPriorityByColumn[columnId] || 'low',
      assignee: 'NA',
      column: 'todo',
      dueDate: '',
    };
    setTasksState((prev) => [...prev, newTask]);
    setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
    setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: 'low' }));
    setShowAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
    taskUpdate({ action: 'create', taskId: id, data: { column: 'todo', title: newTask.title, priority: newTask.priority, assignee: newTask.assignee, dueDate: newTask.dueDate || '' } });
  }, [newTaskPriorityByColumn, newTaskTitleByColumn, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Kanban Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Total: {totalTasks} · Completed: {completedCount}
              </Text>
            </Stack>
            <Badge variant="primary">Live updates: {taskChanged.all.length}</Badge>
          </Row>
        </Card>

        {columnsSafe.length === 0 && (
          <Alert variant="warning" title="No columns">
            No columns available to render.
          </Alert>
        )}

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {columnsSafe.map((column) => {
            const columnTasks = tasksByColumn[column.id] || [];
            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.length === 0 && (
                      <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet.</Text>
                    )}

                    {columnTasks.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center">
                            {editingTaskId === task.id ? (
                              <Input
                                label="Edit task title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                placeholder="Task title"
                              />
                            ) : (
                              <Text as={Clickable} onDoubleClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title); }} weight="semibold">{task.title}</Text>
                            )}
                            <Row gap="var(--ggui-spacing-2)">
                              {editingTaskId === task.id ? (
                                <Row gap="var(--ggui-spacing-2)">
                                  <Text as={Clickable} onClick={() => saveEditTask(task.id)} color="var(--ggui-color-primary-600)">Save</Text>
                                  <Text as={Clickable} onClick={() => { setEditingTaskId(''); setEditingTitle(''); }} color="var(--ggui-color-onSurfaceVariant)">Cancel</Text>
                                </Row>
                              ) : (
                                <Text
                                  as={Clickable}
                                  onClick={() => {
                                    setEditingTaskId(task.id);
                                    setEditingTitle(task.title);
                                  }}
                                  color="var(--ggui-color-primary-600)"
                                >
                                  Edit
                                </Text>
                              )}
                            </Row>
                          </Row>

                          <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                            <Badge variant={getPriorityVariant(task.priority)}>{task.priority}</Badge>
                            <Avatar name={task.assignee} size="sm" />
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Assignee: {task.assignee}</Text>
                            {task.dueDate ? (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Due: {task.dueDate}</Text>
                            ) : (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">No due date</Text>
                            )}
                          </Row>

                          <Select
                            label="Move task"
                            value={task.column}
                            onChange={(value) => moveTask(task.id, value)}
                            options={columnsSafe.map((col) => ({ value: col.id, label: col.name }))}
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {showAddFormByColumn[column.id] ? (
                    <Card padding="var(--ggui-spacing-3)" border shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          placeholder="Enter task title"
                          value={newTaskTitleByColumn[column.id] || ''}
                          onChange={(value) => setNewTaskTitleByColumn((prev) => ({ ...prev, [column.id]: value }))}
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriorityByColumn[column.id] || 'low'}
                          onChange={(value) => setNewTaskPriorityByColumn((prev) => ({ ...prev, [column.id]: (value as 'low' | 'medium' | 'high') }))}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" onPress={() => createTask(column.id)}>Create</Button>
                          <Button
                            variant="ghost"
                            onPress={() => setShowAddFormByColumn((prev) => ({ ...prev, [column.id]: false }))}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Box
                      as={Pressable}
                      onPress={() => setShowAddFormByColumn((prev) => ({ ...prev, [column.id]: true }))}
                      hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                      pressStyle={{ transform: 'scale(0.98)' }}
                      padding="var(--ggui-spacing-2)"
                      background="var(--ggui-color-surfaceVariant)"
                      borderRadius="var(--ggui-shape-radius-md)"
                    >
                      <Text align="center" color="var(--ggui-color-primary-600)">+ Add Task</Text>
                    </Box>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>

  );
}

