interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Place helper components here if needed
const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-primary-100)',
  'post-transition metal': 'var(--ggui-color-info-100)',
  metalloid: 'var(--ggui-color-success-100)',
  nonmetal: 'var(--ggui-color-surfaceVariant)',
  halogen: 'var(--ggui-color-warning-100)',
  'noble gas': 'var(--ggui-color-primary-200)',
  lanthanide: 'var(--ggui-color-success-100)',
  actinide: 'var(--ggui-color-error-100)',
};

const getCategoryColor = (category?: string): string => {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  const normalizedCategory = category.toLowerCase().replace(/-/g, ' ');
  return CATEGORY_COLORS[normalizedCategory] || 'var(--ggui-color-surfaceVariant)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchValue, setSearchValue] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchValue.trim().toLowerCase();
    if (!Array.isArray(props.elements)) return [];
    if (!query) return props.elements;
    return props.elements.filter((element) => {
      const matchesName = (element.name || '').toLowerCase().includes(query);
      const matchesSymbol = (element.symbol || '').toLowerCase().includes(query);
      return matchesName || matchesSymbol;
    });
  }, [props.elements, searchValue]);

  const selectedElement = useMemo(() => {
    if (!Array.isArray(props.elements) || selectedAtomicNumber === null) return null;
    return props.elements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [props.elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    if (!Array.isArray(props.elements)) return [];
    const unique = new Set<string>();
    props.elements.forEach((element) => {
      if (element.category) unique.add(element.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [props.elements]);

  useEffect(() => {
    if (!selectedElement && filteredElements.length > 0 && filteredElements[0].atomicNumber) {
      setSelectedAtomicNumber(filteredElements[0].atomicNumber);
    }
  }, [filteredElements, selectedElement]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Search by name or symbol"
          value={searchValue}
          onChange={setSearchValue}
          type="search"
        />

        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          {filteredElements.length === 0 ? (
            <Alert variant="info" title="No elements found">
              Try a different search term.
            </Alert>
          ) : (
            <Box style={{ overflowX: 'auto' }}>
              <Box
                role="grid"
                aria-label="Periodic table of elements"
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, minmax(56px, 1fr))',
                  gap: 'var(--ggui-spacing-2)',
                  minWidth: '1008px',
                }}
              >
                {filteredElements.map((element, index) => (
                  <Card
                    key={`${element.atomicNumber || index}-${element.symbol || 'el'}`}
                    as={Clickable}
                    role="button"
                    tabIndex={0}
                    aria-label={`${element.name || 'Unknown'} (${element.symbol || '?'})`}
                    onClick={() => setSelectedAtomicNumber(element.atomicNumber || null)}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter' || event.key === ' ') {
                        event.preventDefault();
                        setSelectedAtomicNumber(element.atomicNumber || null);
                      }
                    }}
                    hoverStyle={{
                      shadow: 'var(--ggui-shape-shadow-md)',
                      style: {
                        borderColor: 'var(--ggui-color-primary-600)',
                        transform: 'translateY(-1px)',
                      },
                    }}
                    padding="var(--ggui-spacing-2)"
                    border
                    shadow="none"
                    style={{
                      gridColumn: `${element.col || 1} / span 1`,
                      gridRow: `${element.row || 1} / span 1`,
                      minHeight: '72px',
                      background: getCategoryColor(element.category),
                      borderColor: selectedAtomicNumber === element.atomicNumber
                        ? 'var(--ggui-color-primary-600)'
                        : 'var(--ggui-color-outline)',
                      position: 'relative',
                      outline: selectedAtomicNumber === element.atomicNumber ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: '2px',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant)"
                      style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                    >
                      {element.atomicNumber || '-'}
                    </Text>
                    <Stack justify="center" align="center" style={{ height: '100%' }}>
                      <Text size="xl" weight="bold">{element.symbol || '?'}</Text>
                    </Stack>
                  </Card>
                ))}
              </Box>
            </Box>
          )}
        </Card>

        <Card padding="var(--ggui-spacing-4)" border>
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><strong>Name:</strong> {selectedElement.name || '-'}</Text>
                <Text><strong>Symbol:</strong> {selectedElement.symbol || '-'}</Text>
                <Text><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '-'}</Text>
                <Text><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '-'}</Text>
                <Text><strong>Category:</strong> {selectedElement.category || '-'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-2)">
              {categories.map((category) => (
                <Row key={category} align="center" gap="var(--ggui-spacing-2)">
                  <Box
                    style={{
                      width: '14px',
                      height: '14px',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline)',
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

