  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);

  const maxStock = useMemo(() => {
    const stockValue = typeof props.product?.stock === 'number' ? props.product.stock : 0;
    return stockValue > 0 ? stockValue : 0;
  }, [props.product?.stock]);

  useEffect(() => {
    if (maxStock === 0) {
      setQuantity(1);
      return;
    }
    if (quantity > maxStock) {
      setQuantity(maxStock);
    }
    if (quantity < 1) {
      setQuantity(1);
    }
  }, [maxStock, quantity]);

  const normalizedRating = useMemo(() => {
    const ratingValue = typeof props.product?.rating === 'number' ? props.product.rating : 0;
    if (ratingValue < 0) return 0;
    if (ratingValue > 5) return 5;
    return Math.round(ratingValue);
  }, [props.product?.rating]);

  const priceText = useMemo(() => {
    const amount = typeof props.product?.price === 'number' ? props.product.price : 0;
    const currencySymbol = props.product?.currency ?? '';
    return `${currencySymbol}${amount.toFixed(2)}`;
  }, [props.product?.price, props.product?.currency]);

  const specRows = useMemo(() => {
    if (!Array.isArray(props.product?.specifications)) return [];
    return props.product.specifications
      .map((item, index) => {
        const record = item as Record<string, unknown>;
        const keyValue = typeof record?.key === 'string' ? record.key : `Specification ${index + 1}`;
        const valueValue = typeof record?.value === 'string' || typeof record?.value === 'number' ? String(record.value) : '—';
        return { key: `${keyValue}-${index}`, specKey: keyValue, specValue: valueValue };
      });
  }, [props.product?.specifications]);

  const reviewRows = useMemo(() => {
    if (!Array.isArray(props.product?.reviews)) return [];
    return props.product.reviews.map((item, index) => {
      const record = item as Record<string, unknown>;
      const author = typeof record?.author === 'string' ? record.author : 'Anonymous';
      const text = typeof record?.text === 'string' ? record.text : '';
      const date = typeof record?.date === 'string' ? record.date : '';
      const rating = typeof record?.rating === 'number' ? Math.max(0, Math.min(5, Math.round(record.rating))) : 0;
      return { id: `${author}-${index}`, author, text, date, rating };
    });
  }, [props.product?.reviews]);

