  const lowStock = maxStock > 0 && maxStock <= 5;

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => (prev > 1 ? prev - 1 : 1));
  }, []);

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => {
