              <Heading level={2}>{props.product?.name ?? 'Unnamed Product'}</Heading>
              <Text size="xl" weight="bold" color="var(--ggui-color-primary-700)">
                {priceText}
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Row gap="var(--ggui-spacing-1)" aria-label={`Rating: ${normalizedRating} out of 5`}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <Icon
                      key={`star-${star}`}
                      name={star <= normalizedRating ? 'star' : 'star-off'}
                      color={star <= normalizedRating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                      size={18}
                      aria-hidden
                    />
                  ))}
                </Row>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  ({typeof props.product?.reviewCount === 'number' ? props.product.reviewCount : 0} reviews)
                </Text>
              </Row>
              {!outOfStock ? (
                <Badge variant={lowStock ? 'warning' : 'success'} size="md">
                  {lowStock ? 'Low Stock' : 'In Stock'}
                </Badge>
              ) : (
                <Badge variant="error" size="md">
                  Out of Stock
                </Badge>
              )}
            </Stack>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    {props.product?.description ?? 'No description available.'}
                  </Text>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: specRows.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'specKey', header: 'Specification' },
                      { key: 'specValue', header: 'Value' },
                    ]}
                    data={specRows}
                  />
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: reviewRows.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-4)">
                    {reviewRows.map((review) => (
                      <Card key={review.id} padding="var(--ggui-spacing-4)" shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center">
                            <Text weight="semibold">{review.author}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
                          </Row>
                          <Row gap="var(--ggui-spacing-1)" aria-label={`Rating: ${review.rating} out of 5`}>
                            {[1, 2, 3, 4, 5].map((star) => (
                              <Icon
                                key={`${review.id}-star-${star}`}
                                name={star <= review.rating ? 'star' : 'star-off'}
                                color={star <= review.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                                size={16}
                                aria-hidden
                              />
                            ))}
                          </Row>
                          <Text color="var(--ggui-color-onSurfaceVariant)">{review.text}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Text weight="medium">Quantity</Text>
              <Button
                variant="outline"
                size="sm"
                onPress={handleDecrement}
                disabled={quantity <= 1}
              >
                Decrease quantity
              </Button>
              <Input
                label="Quantity"
                type="number"
                value={String(quantity)}
                onChange={(value) => {
                  const parsed = Number(value);
                  if (Number.isNaN(parsed)) {
                    setQuantity(1);
                    return;
                  }
                  if (parsed < 1) {
                    setQuantity(1);
                    return;
                  }
                  if (maxStock > 0 && parsed > maxStock) {
                    setQuantity(maxStock);
                    return;
                  }
                  setQuantity(parsed);
                }}
              />
              <Button
                variant="outline"
                size="sm"
                onPress={handleIncrement}
                disabled={outOfStock || quantity >= maxStock}
              >
                Increase quantity
              </Button>
              <Spacer size="flex" />
              <Button
                variant="primary"
                onPress={handleAddToCart}
                disabled={outOfStock || !props.product?.id}
              >
                Add to Cart
              </Button>
            </Row>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Available stock: {maxStock}
            </Text>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

