// Place helper components here if needed

function formatTimestamp(value?: string): string {
  if (!value) return '—';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return '—';
  return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<StreamTyping | null>(null);
  const bottomRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessageList(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setMessageList((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingState(typing.latest);
    }
  }, [typing.latest]);

  useEffect(() => {
    if (bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [messageList.length, typingState?.active]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (messageList || []).forEach((item) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === item.sender) {
        last.items.push(item);
      } else {
        groups.push({ sender: item.sender, items: [item] });
      }
    });
    return groups;
  }, [messageList]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setMessageList((prev) => [...prev, { sender: props.currentUser, text: payload.text, timestamp: payload.timestamp }]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="sm">
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
              {typingState?.active && typingState.sender && typingState.sender !== props.currentUser ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typingState.sender} is typing...</Text>
              ) : (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">No one is typing</Text>
              )}
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              {(groupedMessages || []).length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">No messages yet.</Text>
              ) : (
                <Box>
                  <Stack gap="var(--ggui-spacing-3)">
                    {groupedMessages.map((group, groupIndex) => {
                      const isCurrentUser = group.sender === props.currentUser;
                      return (
                        <Stack key={`group-${group.sender || 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender || 'Unknown sender'}</Text>
                          {group.items.map((item, itemIndex) => (
                            <Box
                              key={`msg-${groupIndex}-${itemIndex}-${item.timestamp || item.text || 'x'}`}
                              padding="var(--ggui-spacing-2)"
                              background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                              borderRadius="var(--ggui-shape-radius-md)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="bodySmall"
                                  color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                >
                                  {item.text || ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  align={isCurrentUser ? 'right' : 'left'}
                                >
                                  {formatTimestamp(item.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })}
                    <Box><div ref={bottomRef} /></Box>
                  </Stack>
                </Box>
              )}
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box padding="0" margin="0" background="transparent">
              <Input
                label="Message"
                placeholder="Type your message..."
                value={draft}
                onChange={setDraft}
                helperText="Press Enter to send"
                onKeyDown={(event) => {
                  if (event.key === 'Enter') {
                    event.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Box padding="0" margin="0" background="transparent">
              <Button variant="primary" disabled={!draft.trim()} onClick={handleSend}>
                Send
              </Button>
            </Box>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

