/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
function formatCurrency(value?: number): string {
  const safeValue = typeof value === 'number' ? value : 0;
  return `$${safeValue.toFixed(2)}`;
}

function formatSigned(value?: number): string {
  const safeValue = typeof value === 'number' ? value : 0;
  const prefix = safeValue > 0 ? '+' : '';
  return `${prefix}${safeValue.toFixed(2)}`;
}

function formatSignedPercent(value?: number): string {
  const safeValue = typeof value === 'number' ? value : 0;
  const prefix = safeValue > 0 ? '+' : '';
  return `${prefix}${safeValue.toFixed(2)}%`;
}

function getStockTone(change?: number): { color: string; border: string; bg: string; arrow: string } {
  const safeChange = typeof change === 'number' ? change : 0;
  if (safeChange < 0) {
    return {
      color: 'var(--ggui-color-error-700)',
      border: 'var(--ggui-color-error-500)',
      bg: 'var(--ggui-color-error-50)',
      arrow: '▼',
    };
  }
  return {
    color: 'var(--ggui-color-success-700)',
    border: 'var(--ggui-color-success-500)',
    bg: 'var(--ggui-color-success-50)',
    arrow: '▲',
  };
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    const updateSymbol = priceUpdate.latest.symbol;
    setStocksState((prev) => {
      let found = false;
      const next = prev.map((stock) => {
        if (stock.symbol === updateSymbol) {
          found = true;
          return {
            ...stock,
            price: typeof priceUpdate.latest?.price === 'number' ? priceUpdate.latest.price : stock.price,
            change: typeof priceUpdate.latest?.change === 'number' ? priceUpdate.latest.change : stock.change,
            changePercent: typeof priceUpdate.latest?.changePercent === 'number' ? priceUpdate.latest.changePercent : stock.changePercent,
          };
        }
        return stock;
      });
      if (!found) {
        next.push({
          symbol: priceUpdate.latest?.symbol,
          name: priceUpdate.latest?.symbol,
          price: priceUpdate.latest?.price,
          change: priceUpdate.latest?.change,
          changePercent: priceUpdate.latest?.changePercent,
        });
      }
      return next;
    });
    setLastUpdated(new Date());
    setFlashMap((prev) => ({
      ...prev,
      [updateSymbol]: Date.now(),
    }));
  }, [priceUpdate.latest]);

  const marketStatusLabel = useMemo(() => {
    const raw = marketStatus.latest?.status;
    if (!raw) return 'Unknown';
    return raw.charAt(0).toUpperCase() + raw.slice(1);
  }, [marketStatus.latest]);

  const sortedStocks = useMemo(() => {
    return [...(stocksState ?? [])].sort((a, b) => (a.symbol ?? '').localeCompare(b.symbol ?? ''));
  }, [stocksState]);

  const hasStocks = sortedStocks.length > 0;

  return (
