              <Badge variant={marketStatus.latest?.status === 'open' ? 'success' : marketStatus.latest?.status === 'closed' ? 'error' : 'warning'}>
                {marketStatusLabel}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onContainer)" is="span" aria-live="polite" role="status">
                Live Clock: {now.toLocaleTimeString()}
              </Text>
            </Stack>
          </Row>
        </Box>

        {!hasStocks ? (
          <Alert variant="info" title="No stocks to display">
            Waiting for stock data from props or live stream updates.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {sortedStocks.map((stock, index) => {
              const tone = getStockTone(stock.change);
              const symbol = stock.symbol ?? `STK-${index}`;
              const flashKey = flashMap[symbol] ?? 0;
              return (
                <Card
                  key={`${symbol}-${flashKey}`}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                >
                  <Box
                    padding="var(--ggui-spacing-3)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background="var(--ggui-color-surfaceVariant)"
                    margin="0"
                    style={{
                      border: `1px solid ${tone.border}`,
                      animation: flashMap[symbol] ? 'ggui-flash 500ms ease-out' : 'none',
                      ['--ggui-flash-color' as string]: tone.bg,
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row justify="between" align="center">
                        <Heading level={3} color="var(--ggui-color-onSurface)">
                          {stock.symbol ?? 'N/A'}
                        </Heading>
                        <Badge variant={stock.change && stock.change < 0 ? 'error' : 'success'}>
                          {stock.change && stock.change < 0 ? 'Down' : 'Up'}
                        </Badge>
                      </Row>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                        {formatCurrency(stock.price)}
                      </Text>
                      <Divider margin="var(--ggui-spacing-1)" color="var(--ggui-color-outlineVariant)" />
                      <Row justify="between" align="center">
                        <Text variant="label" color={tone.color}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Text variant="label" color={tone.color}>
                          <Text is="span" aria-hidden="true" color={tone.color}>
                            {tone.arrow}
                          </Text>{' '}
                          <Text is="span" variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {stock.change && stock.change < 0 ? 'down' : 'up'}
                          </Text>{' '}
                          {formatSignedPercent(stock.changePercent)}
                        </Text>
                      </Row>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" is="span" aria-live="polite" role="status">
                        {`Update for ${stock.symbol ?? 'stock'}: ${formatCurrency(stock.price)}, ${formatSigned(stock.change)} (${formatSignedPercent(stock.changePercent)})`}
                      </Text>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const resolvedAvatarOptions = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) {
      return props.avatarOptions.slice(0, 4);
    }
    return ['😀', '🚀', '🎨', '🧠'];
  }, [props.avatarOptions]);

  const resolvedRoleOptions = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? (resolvedAvatarOptions[0] ?? '😀'));
  const [role, setRole] = useState(props.initialProfile.role ?? (resolvedRoleOptions[0] ?? 'Developer'));
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  const [attemptedNext, setAttemptedNext] = useState(false);

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar ?? (resolvedAvatarOptions[0] ?? '😀'));
    setRole(props.initialProfile.role ?? (resolvedRoleOptions[0] ?? 'Developer'));
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  }, [props.initialProfile, resolvedAvatarOptions, resolvedRoleOptions]);

  const isEmailValid = useMemo(() => EMAIL_REGEX.test(email.trim()), [email]);
  const isNameValid = useMemo(() => name.trim().length > 0, [name]);
  const isStep1Valid = isNameValid && isEmailValid;
  const canGoNext = step === 1 ? isStep1Valid : step === 2;
  const progressValue = (step / 3) * 100;

  const handleNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) {
      setAttemptedNext(true);
      return;
    }
    setAttemptedNext(false);
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, isStep1Valid]);

  const handleBack = useCallback(() => {
    setAttemptedNext(false);
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
  }, [name, email, avatar, role, emailNotifications, theme, complete]);
  const nameError = attemptedNext && !isNameValid ? 'Name is required.' : undefined;
  const emailError = attemptedNext && !email.trim() ? 'Email is required.' : attemptedNext && !isEmailValid ? 'Enter a valid email address.' : undefined;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
            <Row gap="var(--ggui-spacing-2)" wrap>
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          border
          radius="lg"
          style={{
            animation: 'ggui-fadeIn 200ms ease-out',
            background: 'var(--ggui-color-surfaceVariant)',
          }}
        >
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={emailError}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurface)">Choose an avatar</Text>
                  <Box role="radiogroup" aria-label="Choose an avatar">
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {resolvedAvatarOptions.map((option) => (
                        <Button
                          key={option}
                          variant={avatar === option ? 'primary' : 'outline'}
                          onClick={() => setAvatar(option)}
                          aria-pressed={avatar === option}
                          role="radio"
                          aria-checked={avatar === option}
                        >
                          {option}
                        </Button>
                      ))}
                    </Row>
                  </Box>
                </Stack>
              </Stack>
            )}
            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={resolvedRoleOptions.map((item) => ({ value: item, label: item }))}
                  placeholder="Select your role"
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Theme preference (Dark mode)"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your details">
                  Confirm everything looks correct before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>
        </Card>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={handleBack}>Go Back</Button>
                <Button variant="primary" onClick={handleComplete}>Complete Setup</Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
